async function execute(api: TaskFlowScriptAPI, params: FlowParams): Promise<TaskFlowScriptResult> {
    const chartPage = await api.webFetch(
        `https://www.chosic.com/genre-chart/${params.genre}/tracks/2025/`,
    );

    const songs = await api.queryLLM(
        `Extract song titles and artists from the following page. Return ONLY a JSON array of objects with "trackName" and "artist" fields, limited to the top ${params.quantity}. If you cannot find any songs with both a title and artist, return an empty array []. Output nothing except the JSON array.`,
        { input: chartPage.text, parseJson: true },
    );

    if (!Array.isArray(songs.data) || songs.data.length === 0) {
        return { success: false, error: "Could not extract songs from the chart page" };
    }

    const result = await api.callAction("player", "createPlaylist", {
        name: `Top ${params.quantity} ${params.genre} \u2013 ${params.timePeriod}`,
        songs: songs.data,
    });

    return { success: true, message: result.text, data: result.data };
}
